INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('e3d73b43e40c0cecbc9b4094e7340c2a8d629f341c13bab0d92aa41e37f88432','Mid Semester','Programming for Problem Solving','CS24101','1','2024','Q.1(a)','List various responsibilities of an operating system.','\\text{List various responsibilities of an operating system.}','An operating system acts as an interface between hardware and the user. Its primary responsibilities include: 1. Process Management: Managing CPU scheduling, creating, and terminating processes. 2. Memory Management: Tracking memory usage, allocating, and deallocating space for processes. 3. File Management: Organizing files in directories and controlling access rights. 4. Device Management: Handling input/output operations through drivers. 5. Security and Protection: Ensuring data privacy and preventing unauthorized access. 6. Resource Allocation: Managing system resources like CPU time and I/O devices among multiple users or processes.','\\text{The primary responsibilities of an operating system are as follows:} \\\\ 1. \\text{Process Management: Scheduling processes and threads, managing inter-process communication.} \\\\ 2. \\text{Memory Management: Managing primary memory via allocation, deallocation, and virtual memory techniques.} \\\\ 3. \\text{File Management: Handling file creation, deletion, and directory manipulation.} \\\\ 4. \\text{Device Management: Managing hardware I/O via device drivers.} \\\\ 5. \\text{Security and Protection: Enforcing authentication, authorization, and resource access control.} \\\\ 6. \\text{Resource Allocation: Efficient distribution of system resources (CPU, disk, network) among concurrent tasks.}','Process Management, Memory Management, File Management, Device Management, Security/Protection, and Resource Allocation.','["Computer Components", "Operating System"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('02f21fc36d25c6a9ea60f185149d5c4be805db6ab6a397f8e4dda1f6d798b405','Mid Semester','Programming for Problem Solving','CS24101','1','2024','Q.1(b)','Draw a block diagram of the computer system and explain its various components with special emphasis on storage.','\\text{Draw a block diagram of the computer system and explain its various components with special emphasis on storage.}','Step 1: Identify the fundamental components of a computer system based on the von Neumann architecture. These are the Central Processing Unit (CPU), Input Unit, Output Unit, and Memory Unit (Storage). Step 2: Define the CPU. It acts as the brain of the computer, consisting of the Arithmetic Logic Unit (ALU) for calculations, the Control Unit (CU) for instruction management, and registers for temporary high-speed storage. Step 3: Define Input and Output units. Input devices (keyboard, mouse) translate human-readable data into machine-readable format. Output units (monitor, printer) translate machine results into human-readable format. Step 4: Explain the Storage/Memory unit with emphasis. Primary Storage (RAM/ROM) is volatile, high-speed, and directly accessed by the CPU. Secondary Storage (HDD, SSD, Flash) is non-volatile, high-capacity, and stores long-term data. It serves as a persistent repository for files and software that is loaded into primary memory when required. Step 5: Describe the flow of data. Data moves from input to memory, is processed by the CPU, and is sent to output, with the system bus acting as the interconnection mechanism.','The block diagram consists of the following components interconnected by the system bus (Data, Address, and Control buses): 1. Input Unit: Converts external information into digital signals. 2. CPU (Central Processing Unit): Comprised of: (a) Arithmetic Logic Unit (ALU): Performs logical and arithmetic operations. (b) Control Unit (CU): Orchestrates system operations. (c) Registers: High-speed internal storage. 3. Memory/Storage Unit: (a) Primary Storage: Volatile memory (RAM) providing immediate access to the CPU for active processes. (b) Secondary Storage: Non-volatile, high-density storage (SSD, HDD) providing permanent persistence. Its hierarchy is defined by access time: Registers > Cache > RAM > Secondary Storage. 4. Output Unit: Converts digital output into human-comprehensible formats. The relationship is defined as: Input -> [Memory <-> CPU] -> Output.','Computer System = {Input, CPU (ALU, CU, Registers), Memory (Primary/Secondary), Output}','["Computer Systems", "Hardware Architecture"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('3f4fb12939c9972dc9afe0eeadf355986c77e5cf56796679195ee47de1064275','Mid Semester','Programming for Problem Solving','CS24101','1','2024','Q.2(a)','Define the term algorithm and explain the characteristics of a good algorithm.','\\text{Define the term algorithm and explain the characteristics of a good algorithm.}','An algorithm is a well-defined sequence of computational steps that takes a set of values as input and produces a set of values as output to solve a specific problem. A good algorithm must possess five key characteristics: 1. Input: Zero or more quantities are externally supplied. 2. Output: At least one quantity is produced. 3. Definiteness: Each step must be clear and unambiguous. 4. Finiteness: The algorithm must terminate after a finite number of steps. 5. Effectiveness: Every instruction must be sufficiently basic to be carried out exactly and in a finite amount of time by a person or machine.','\\text{An algorithm is a finite, unambiguous, and effective step-by-step procedure to solve a computational problem. Its characteristics are:} \\\\ \\text{1. Input: Zero or more input values are provided.} \\\\ \\text{2. Output: At least one value is generated.} \\\\ \\text{3. Definiteness: Each step is precisely defined.} \\\\ \\text{4. Finiteness: The algorithm terminates in a finite number of steps.} \\\\ \\text{5. Effectiveness: Operations are simple enough to be performed exactly.}','An algorithm is a finite, unambiguous, and effective sequence of instructions. Characteristics include Input, Output, Definiteness, Finiteness, and Effectiveness.','["Algorithms", "Problem Solving"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('32e127e96a6cf162b15a3b83da683ae4339ce214b350708aca12f16549e8956f','Mid Semester','Programming for Problem Solving','CS24101','1','2024','Q.2(b)','Write a pseudocode and draw the corresponding flow chart where multiple conditions are checked to categorize a person based on specified age as either child (<12 years), teenager (>=12 years but <19 years) or adult (>19 years).','\\text{Write a pseudocode and draw the corresponding flow chart where multiple conditions are checked to categorize a person based on specified age as either child } (<12 \\text{ years}), \\text{ teenager } (\\ge 12 \\text{ years but } <19 \\text{ years}) \\text{ or adult } (>19 \\text{ years}).','Conceptual Analysis: The problem requires categorizing an individual into one of three age groups based on a numerical input (age). We use conditional branching. Step 1: Input age. Step 2: If age is less than 12, print \'Child\'. Step 3: If age is between 12 and 18 inclusive (i.e., < 19), print \'Teenager\'. Step 4: If age is greater than or equal to 19, print \'Adult\'. Interpretation: This logic ensures mutually exclusive classification across all non-negative integers. Pseudocode: 1. Start. 2. Read age. 3. If age < 12, display \'Child\'. 4. Else if age < 19, display \'Teenager\'. 5. Else, display \'Adult\'. 6. Stop. Flowchart Description: Start -> Input Age -> Decision node (Age < 12) -> [Yes: Print Child] or [No: Decision node (Age < 19)] -> [Yes: Print Teenager] or [No: Print Adult] -> End.','Algorithm:\\\\ 1. \\text{Start}\\\\ 2. \\text{Input } age\\\\ 3. \\text{If } age < 12: \\text{ Print \'Child\'}\\\\ 4. \\text{Else if } age < 19: \\text{ Print \'Teenager\'}\\\\ 5. \\text{Else: Print \'Adult\'}\\\\ 6. \\text{Stop}\\\\ \\\\ \\text{Flowchart Logic:}\\\\ \\text{Start} \\to [\\text{Input } age] \\to [\\text{Is } age < 12?] \\xrightarrow{Yes} [\\text{Print \'Child\'}] \\xrightarrow{End}\\\\ \\downarrow No\\\\ [\\text{Is } age < 19?] \\xrightarrow{Yes} [\\text{Print \'Teenager\'}] \\xrightarrow{End}\\\\ \\downarrow No\\\\ [\\text{Print \'Adult\'}] \\to [\\text{End}]','Classification: age < 12 -> Child; 12 <= age < 19 -> Teenager; age >= 19 -> Adult','["Conditionals", "Flowcharts", "Pseudocode"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('fcd95c2d6c1253af0d5a5ae7bde18a47a6a63a30e71383ff603f3fa11e4cb18e','Mid Semester','Programming for Problem Solving','CS24101','2','2024','Q.3(a)','Compute the value of x and y for the following expressions with their evaluation tree: (i) x = !0 || 4.0 + 2.0 >= 3.0 - 2.0 (ii) y = 75 - 20 - 48 / 8 * 5 + 9 % 2 + 10 >> 2.','\\text{Compute the value of } x \\text{ and } y \\text{ for the following expressions with their evaluation tree: (i) } x = !0 \\parallel 4.0 + 2.0 \\ge 3.0 - 2.0 \\text{ (ii) } y = 75 - 20 - 48 / 8 * 5 + 9 \\% 2 + 10 \\gg 2.','For expression (i), we evaluate using operator precedence: Logical NOT (!) has the highest precedence, followed by arithmetic (+, -), then relational (>=), and finally logical OR (||). First, !0 evaluates to true (1). Next, 4.0+2.0=6.0 and 3.0-2.0=1.0. 6.0 >= 1.0 is true (1). Thus, 1 || 1 evaluates to 1. For expression (ii), we follow C precedence rules: *, /, % (left-to-right), then +, - (left-to-right), and finally >>. Step 1: 48/8=6. Step 2: 6*5=30. Step 3: 9%2=1. Step 4: 75-20=55. Step 5: 55-30=25. Step 6: 25+1=26. Step 7: 26+10=36. Step 8: 36 >> 2 (36 / 2^2 = 36/4) = 9.','i) x = !0 \\parallel 4.0 + 2.0 \\ge 3.0 - 2.0. \\text{ Precedence: } (!), (+, -), (\\ge), (\\parallel). \\\\ !0 \\to 1. \\\\ 4.0+2.0 = 6.0, \\; 3.0-2.0 = 1.0. \\\\ 6.0 \\ge 1.0 \\to 1. \\\\ x = 1 \\parallel 1 = 1. \\\\ ii) y = 75 - 20 - 48 / 8 * 5 + 9 \\% 2 + 10 \\gg 2. \\\\ \\text{Precedence: } (*, /, \\%), (+, -), (\\gg). \\\\ 1) 48 / 8 = 6. \\\\ 2) 6 * 5 = 30. \\\\ 3) 9 \\% 2 = 1. \\\\ 4) 75 - 20 = 55. \\\\ 5) 55 - 30 = 25. \\\\ 6) 25 + 1 = 26. \\\\ 7) 26 + 10 = 36. \\\\ 8) 36 \\gg 2 = 9.','x = 1, y = 9','["Expressions", "Operators", "Precedence"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('bb34f71569425cec9fec50f15aa959a220407e5ae5fbb5c5179d28af5ab5b979','Mid Semester','Programming for Problem Solving','CS24101','1','2024','Q.3(b)','Illustrate various programming errors in C with examples.','\\text{Illustrate various programming errors in C with examples.}','Programming errors in C are categorized into four types: 1. Syntax Errors: Occur when rules of the language are violated, such as missing semicolons. 2. Runtime Errors: Occur during execution, such as division by zero or segmentation faults. 3. Logical Errors: The program runs but produces incorrect results due to flawed algorithms. 4. Linker Errors: Occur during the linking phase, often due to misspelled function names or missing library files.','\\text{1. Syntax Error: Violating language grammar. Example: } printf(\\"Hello\\" ) \\text{ (missing semicolon).} \\\\ \\text{2. Runtime Error: Abnormal termination. Example: } int a = 10 / 0; \\text{ (division by zero).} \\\\ \\text{3. Logical Error: Incorrect output. Example: } if (x = 5) \\text{ instead of } if (x == 5); \\text{ this performs assignment instead of comparison.} \\\\ \\text{4. Linker Error: Symbol resolution failure. Example: Calling a function } func() \\text{ without defining or including its prototype.}','Errors in C: Syntax, Runtime, Logical, and Linker.','["Compilation", "Logical Errors", "Syntax Errors"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('668da681faddfa0165b6672bedff7cc6dc3d836c040ffca5b23f9ddce3d1aa9d','Mid Semester','Programming for Problem Solving','CS24101','2','2024','Q.4(a)','Illustrate the difference between prefix and postfix increment operator with examples.','\\text{Illustrate the difference between prefix and postfix increment operator with examples.}','1. Prefix increment (++i): The variable is incremented first, and then the updated value is used in the expression. If i=5, ++i results in 6, and the expression uses 6.\n2. Postfix increment (i++): The current value of the variable is used in the expression first, and then the variable is incremented. If i=5, i++ results in 5 being used in the expression, after which i becomes 6.\n3. Example: If int a = 5, int b = ++a sets b=6 and a=6. If int c = 5, int d = c++ sets d=5 and c=6.','\\text{Prefix Increment (}\\!+\\!+\\!i\\text{): Increment then Use. The value is updated before evaluation. Example: } a=5, b=\\!+\\!+\\!a \\implies a=6, b=6. \\text{ Postfix Increment (}i\\!+\\!+\\text{): Use then Increment. The current value is evaluated, then updated. Example: } c=5, d=c\\!+\\!+\\implies c=6, d=5.','Prefix (++i): Increment before use; Postfix (i++): Increment after use.','["Increment Operator", "Operators"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('73bab0c50cbb71e2b8df26bf9cc8a6ab6448de297ca2bcdaefa63161a0548c34','Mid Semester','Programming for Problem Solving','CS24101','2','2024','Q.4(b)','Differentiate between nested if-else and switch-case statement with examples.','\\text{Differentiate between nested if-else and switch-case statement with examples.}','1. Nested if-else: This structure involves placing one if-else statement inside another. It is highly flexible and can evaluate complex logical conditions involving ranges or multiple variables. It uses boolean evaluations at every stage. 2. Switch-case: This is a multi-way branch statement that compares a single integer or character expression against a set of constant values. It is efficient for discrete, equality-based checks. 3. Key Differences: Nested if-else supports ranges and complex conditions, whereas switch-case supports only equality tests with discrete constant values. Switch-case is often more readable for menu-driven programs, while nested if-else is necessary for complex logic.','\\begin{enumerate} \\item \\textbf{Nested if-else:} Structures where if-else blocks are nested. Example: \\text{if(a>b)\\{ if(a>c) max=a; else max=c; \\} else \\{ if(b>c) max=b; else max=c; \\}} \\item \\textbf{Switch-case:} A jump table approach for discrete values. Example: \\text{switch(choice)\\{ case 1: print("One"); break; default: print("Other"); \\}} \\item \\textbf{Comparison:} Nested if-else allows boolean ranges (e.g., x > 10 && x < 20), whereas switch-case is restricted to constant integral equality (e.g., case 1:). \\end{enumerate}','Nested if-else is for range-based/logical complexity, while switch-case is for discrete equality matching.','["Conditional Branching", "Switch Case"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('27b88f9423eeabd2dfc6adf14122ad947757607c0dd23f6b8a3b87cf0848bc4c','Mid Semester','Programming for Problem Solving','CS24101','2','2023','Q.1(a)','Explain any two examples of each of the following operators. a) Arithmetic operators b) Logical operators.','\\text{Explain any two examples of each of the following operators. a) Arithmetic operators b) Logical operators.}','a) Arithmetic Operators: These are used to perform mathematical operations. 1. Addition (+): Adds two operands. Example: 5 + 3 = 8. 2. Subtraction (-): Subtracts the second operand from the first. Example: 10 - 4 = 6. b) Logical Operators: These are used to combine conditional statements. 1. Logical AND (&&): Returns true if both operands are true. Example: (5 > 3 && 2 < 4) is true. 2. Logical OR (||): Returns true if at least one of the operands is true. Example: (5 > 10 || 2 < 4) is true.','\\text{a) Arithmetic Operators: Used for mathematical calculations.} \\\\ 1. \\text{Addition (+): Adds two values. Example: } 5 + 3 = 8. \\\\ 2. \\text{Subtraction (-): Subtracts one value from another. Example: } 10 - 4 = 6. \\\\ \\text{b) Logical Operators: Used for logical evaluations.} \\\\ 1. \\text{Logical AND (&&): Returns true if both conditions are true. Example: } (5 > 3) \\land (2 < 4) \\implies \\text{True}. \\\\ 2. \\text{Logical OR (||): Returns true if at least one condition is true. Example: } (5 > 10) \\lor (2 < 4) \\implies \\text{True}.','Arithmetic: (+, -), Logical: (&&, ||)','["Arithmetic Operators", "Logical Operators", "Operators"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('af784103461c91f404057b99c6ba4d4bb66cb6b654ef775b2331c21cb93ae0d4','Mid Semester','Programming for Problem Solving','CS24101','2','2023','Q.1(b)','Explain briefly about each line of code in the following program: #include<stdio.h> void main() ( int a=10; float b=23.56; char c=\'A\'; printf("%d %f %c\\n", a,b,c); )','\\begin{array}{l} \\text{Explain briefly about each line of code in the following program:} \\\\ \\texttt{\\#include<stdio.h>} \\\\ \\texttt{void main()} \\\\ \\texttt{\\{} \\\\ \\texttt{\\ \\ int a=10;} \\\\ \\texttt{\\ \\ float b=23.56;} \\\\ \\texttt{\\ \\ char c=\'A\';} \\\\ \\texttt{\\ \\ printf("\\%d \\%f \\%c\\\\n", a,b,c);} \\\\ \\texttt{\\}} \\end{array}','1. #include<stdio.h>: This is a preprocessor directive that includes the Standard Input Output library, enabling the use of functions like printf. 2. void main(): This defines the main function, which is the entry point of the C program. The \'void\' return type indicates that the function returns no value. 3. {: Marks the beginning of the function body. 4. int a=10;: Declares an integer variable \'a\' and initializes it with the value 10. 5. float b=23.56;: Declares a floating-point variable \'b\' and initializes it with 23.56. 6. char c=\'A\';: Declares a character variable \'c\' and initializes it with the character \'A\'. 7. printf("%d %f %c\\n", a,b,c);: This function prints the values of a, b, and c to the console. %d, %f, and %c are format specifiers for integer, float, and character respectively, and \\n represents a newline character. 8. }: Marks the end of the function body.','\\begin{itemize} \\item \\texttt{\\#include<stdio.h>}: Includes standard input/output definitions. \\item \\texttt{void main()}: Entry point of the program. \\item \\texttt{\\{}: Start of the main code block. \\item \\texttt{int a=10;}: Initialization of integer variable \\textit{a}. \\item \\texttt{float b=23.56;}: Initialization of floating-point variable \\textit{b}. \\item \\texttt{char c=\'A\';}: Initialization of character variable \\textit{c}. \\item \\texttt{printf("\\%d \\%f \\%c\\n", a,b,c);}: Outputs variables using format specifiers for integer, float, and character. \\item \\texttt{\\}}: End of the code block. \\end{itemize}','The program defines three variables (int, float, char) and displays their values in the console using formatted output.','["Basic I/O", "Data Types", "Programming Concepts", "Structure of C Program"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('5f8dfdc9782ea51ef3a236fc9ca3e545c32ba04045f22c5f94d3e668af6d6bf6','Mid Semester','Programming for Problem Solving','CS24101','1','2023','Q.2(a)','Make a flow chart to find out whether a number is an odd number or even number, if any integer number is input through keyboard.','\\text{Make a flow chart to find out whether a number is an odd number or even number, if any integer number is input through keyboard.}','To determine if an integer is even or odd, we use the property of divisibility by 2. An even number is any integer exactly divisible by 2 (remainder 0), while an odd number leaves a remainder of 1. Step 1: Start. Step 2: Input an integer \'n\'. Step 3: Calculate the remainder of n divided by 2 (n % 2). Step 4: If the remainder is 0, the number is even; otherwise, it is odd. Step 5: Display the result. Step 6: Stop.','\\text{Step 1: Start} \\\\ \\text{Step 2: Read integer } n \\\\ \\text{Step 3: Calculate } r = n \\pmod{2} \\\\ \\text{Step 4: Check if } r = 0 \\\\ \\text{If true, print \'Even\'} \\\\ \\text{If false, print \'Odd\'} \\\\ \\text{Step 5: Stop}','If n % 2 == 0, then Even; else Odd.','["Conditionals", "Flowcharts"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('3bf845ef3a28d83522621d349343aaec635d81bf092fbe03dbe6799c5fbb5cdf','Mid Semester','Programming for Problem Solving','CS24101','2','2023','Q.2(b)','Write all steps to solve expression involving integer values only which is based on precedence and associativity concept. 5*(10/5+ (7*6-3)% (6+5-2)).','\\text{Write all steps to solve expression involving integer values only which is based on precedence and associativity concept. } 5*(10/5+ (7*6-3)\\% (6+5-2)).','To solve the expression 5 * (10 / 5 + (7 * 6 - 3) % (6 + 5 - 2)), we follow the order of operations (PEMDAS/BODMAS): parentheses, multiplication, division, and modulo. Step 1: Resolve the inner parentheses. (7 * 6 - 3) becomes (42 - 3) = 39. (6 + 5 - 2) becomes (11 - 2) = 9. Step 2: The expression is now 5 * (10 / 5 + 39 % 9). Step 3: Perform division and modulo inside the outer parenthesis. 10 / 5 = 2. 39 % 9 = 3 (since 39 = 9 * 4 + 3). Step 4: The expression is now 5 * (2 + 3). Step 5: Solve the final parenthesis, 2 + 3 = 5. Step 6: Multiply, 5 * 5 = 25.','Expression: 5 * (10 / 5 + (7 * 6 - 3) \\% (6 + 5 - 2)) \\\\ Step 1: Inner Parentheses \\\\ 5 * (10 / 5 + (42 - 3) \\% (11 - 2)) \\\\ 5 * (10 / 5 + 39 \\% 9) \\\\ Step 2: Division and Modulo \\\\ 5 * (2 + 3) \\\\ Step 3: Addition \\\\ 5 * 5 \\\\ Step 4: Multiplication \\\\ 25','25','["Expressions", "Operators", "Precedence"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('721338b20a0edad8fd51afaa1443170ebd9cf2ebfc66017b7df22400eb873f47','Mid Semester','Programming for Problem Solving','CS24101','1','2023','Q.3(a)','Write any four common flowchart symbols along with their meaning.','\\text{Write any four common flowchart symbols along with their meaning.}','To represent algorithmic processes using flowcharts, specific standardized symbols are employed. Here are four fundamental symbols: 1. Oval (Terminator): Represents the start or end point of a flowchart. 2. Parallelogram (Input/Output): Used for inputting data or displaying output results. 3. Rectangle (Process): Represents a computational step, calculation, or internal data operation. 4. Diamond (Decision): Indicates a conditional operation, typically resulting in two branches (e.g., True/False or Yes/No).','\\begin{itemize} \\item \\textbf{Oval (Terminator):} Used to denote the Start or End point of an algorithm. \\item \\textbf{Parallelogram (Input/Output):} Represents the input of data or the output of information to the user. \\item \\textbf{Rectangle (Process):} Represents any internal process, arithmetic operation, or data manipulation. \\item \\textbf{Diamond (Decision):} Indicates a decision-making point where the flow splits based on a condition (True/False). \\end{itemize}','1. Oval: Start/End, 2. Parallelogram: Input/Output, 3. Rectangle: Process, 4. Diamond: Decision','["Algorithms", "Flowcharts"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('85b9e86f2b8d0af9bc6d60924434e1318050e3e75027a88b7959bf9d5d7ecc3a','Mid Semester','Programming for Problem Solving','CS24101','2','2023','Q.3(b)','Write a program to calculate the sum of the digits of a 3-digit input number.','\\text{Write a program to calculate the sum of the digits of a 3-digit input number.}','To calculate the sum of the digits of a 3-digit number \'n\', we can use modular arithmetic. Step 1: Extract the last digit (units place) using \'n % 10\'. Step 2: Update the number by performing integer division \'n // 10\' to discard the last digit. Step 3: Repeat the process to extract the second digit (tens place) and finally the third digit (hundreds place). Step 4: Sum these three extracted digits.','Let the 3-digit number be represented as n = 100a + 10b + c, where a, b, c are digits and a \\in {1, ..., 9}, b, c \\in {0, ..., 9}. The algorithm is: 1) d_1 = n \\pmod{10} = c. 2) n_1 = \\lfloor n / 10 \\rfloor = 10a + b. 3) d_2 = n_1 \\pmod{10} = b. 4) d_3 = \\lfloor n_1 / 10 \\rfloor = a. 5) \\text{Sum} = d_1 + d_2 + d_3.','Sum = (n \\% 10) + ((n // 10) \\% 10) + (n // 100)','["Arithmetic Operators", "Basic I/O"]','programming','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('2eca8a730d5203a65a9d7e736fc39893caad841e0a9d8c549e55d8a02666d008','Mid Semester','Programming for Problem Solving','CS24101','3','2023','Q.4(a)','Find the output of the following program: #include <stdio.h> void main() ( int i=0, x=0; for (i=1;i<5;++i) ( if (i%2==1) x+=i; else x--; ) printf("%d",x); )','\\begin{array}{l} \\text{Find the output of the following program:} \\\\ \\texttt{\\#include <stdio.h>} \\\\ \\texttt{void main()} \\\\ \\texttt{\\{} \\\\ \\texttt{\\ \\ int i=0, x=0;} \\\\ \\texttt{\\ \\ for (i=1;i<5;++i)} \\\\ \\texttt{\\ \\ \\{} \\\\ \\texttt{\\ \\ \\ \\ if (i\\%2==1)} \\\\ \\texttt{\\ \\ \\ \\ \\ \\ x+=i;} \\\\ \\texttt{\\ \\ \\ \\ else} \\\\ \\texttt{\\ \\ \\ \\ \\ \\ x--;} \\\\ \\texttt{\\ \\ \\ \\}} \\\\ \\texttt{\\ \\ printf("\\%d",x);} \\\\ \\texttt{\\}} \\end{array}','The program initializes variables i and x to 0. A for loop runs from i=1 to i=4. Inside the loop, if i is odd (i%2==1), the current value of i is added to x. If i is even, x is decremented by 1. Iteration 1: i=1, 1 is odd, so x = 0 + 1 = 1. Iteration 2: i=2, 2 is even, so x = 1 - 1 = 0. Iteration 3: i=3, 3 is odd, so x = 0 + 3 = 3. Iteration 4: i=4, 4 is even, so x = 3 - 1 = 2. After the loop, the program prints the final value of x, which is 2.','\\text{The loop executes for } i = 1, 2, 3, 4. \\text{ Initial state: } x = 0. \\\\ i=1: 1 \\pmod 2 = 1 \\implies x = x + 1 = 0 + 1 = 1 \\\\ i=2: 2 \\pmod 2 = 0 \\implies x = x - 1 = 1 - 1 = 0 \\\\ i=3: 3 \\pmod 2 = 1 \\implies x = x + 3 = 0 + 3 = 3 \\\\ i=4: 4 \\pmod 2 = 0 \\implies x = x - 1 = 3 - 1 = 2 \\\\ \\text{Final result: } x = 2.','2','["Conditionals", "Loops", "Output Tracing", "Programming Concepts"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('7e732dacef0e57a4e663b2dbb024a8fce894c0fa48ad8233311c5d478b44b287','End Semester','Programming for Problem Solving','CS24101','1','2023','Q.1(a)','Solve the following equation using a flowchart and algorithm: AX²+BX+C=0.','\\text{Solve the following equation using a flowchart and algorithm: } AX^{2}+BX+C=0.','1. Analysis: The quadratic equation AX^2 + BX + C = 0 requires calculating the discriminant D = B^2 - 4AC. If D > 0, there are two real distinct roots. If D = 0, there is one repeated real root. If D < 0, there are two complex roots. 2. Algorithm: Start. Input A, B, C. Calculate D = B^2 - 4AC. If A = 0, treat as a linear equation. Otherwise: If D >= 0, compute x1 = (-B + sqrt(D))/(2A) and x2 = (-B - sqrt(D))/(2A). If D < 0, compute real part -B/(2A) and imaginary part sqrt(|D|)/(2A). Display results. Stop. 3. Flowchart Logic: Start -> Input A, B, C -> Check A==0 -> Check D>=0 -> Calculate roots based on D sign -> Output roots -> Stop.','The roots of the quadratic equation AX^{2}+BX+C=0 are determined by the quadratic formula: x = \\frac{-B \\pm \\sqrt{B^{2}-4AC}}{2A}. \\text{ Step 1: Calculate discriminant } D = B^{2}-4AC. \\text{ Step 2: Case 1: If } A=0, \\text{ solve linear equation } BX+C=0 \\implies x = -C/B. \\text{ Step 3: Case 2: If } D \\geq 0, \\text{ roots are } x_{1,2} = \\frac{-B \\pm \\sqrt{D}}{2A}. \\text{ Step 4: Case 3: If } D < 0, \\text{ roots are complex: } x = \\frac{-B}{2A} \\pm i\\frac{\\sqrt{|D|}}{2A}.','x = \\frac{-B \\pm \\sqrt{B^{2}-4AC}}{2A}','["Algorithms", "Flowcharts"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('9d8f5884888c02268252387dc69890c6c913cacbf9675f8b73e41d06699d9df4','End Semester','Programming for Problem Solving','CS24101','1','2023','Q.1(b)','What do you mean by algorithm? Explain briefly about properties of the algorithm.','\\text{What do you mean by algorithm? Explain briefly about properties of the algorithm.}','An algorithm is a step-by-step, finite sequence of well-defined instructions designed to perform a specific task or solve a computational problem. It serves as a blueprint for writing computer programs. The essential properties of an algorithm include: 1. Input: Zero or more quantities are externally supplied. 2. Output: At least one quantity is produced as a result. 3. Definiteness: Each instruction must be clear, unambiguous, and precise. 4. Finiteness: The algorithm must terminate after a finite number of steps. 5. Effectiveness: Every operation must be basic enough to be performed exactly and in a finite amount of time.','\\text{An algorithm is a finite sequence of unambiguous instructions to solve a problem. Its key properties are: (i) \\textbf{Input}: Zero or more inputs. (ii) \\textbf{Output}: At least one output. (iii) \\textbf{Definiteness}: Each step is clearly defined. (iv) \\textbf{Finiteness}: The algorithm terminates after finite steps. (v) \\textbf{Effectiveness}: Steps are feasible and executable.}','An algorithm is a finite, unambiguous, effective sequence of instructions. Key properties: Input, Output, Definiteness, Finiteness, and Effectiveness.','["Algorithms"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('e72e9942bc4718a2959346e7648d1a585e25cdb7d24b1596deca32674f934316','End Semester','Programming for Problem Solving','CS24101','3','2023','Q.2(a)','Find the output of the following fragment of code given in C language: a) for (int x=2; x<=6; x++) ( if (x>4) break; printf("%d", x); ) b) int num = 10; int a; a = num++; printf("num is %d, a is %d", num, a);','\\begin{array}{l} \\text{Find the output of the following fragment of code given in C language:} \\\\ \\text{a) } \\texttt{for (int x=2; x<=6; x++) \\{ if (x>4) break; printf("\\%d", x); \\}} \\\\ \\text{b) } \\texttt{int num = 10; int a; a = num++; printf("num is \\%d, a is \\%d", num, a);} \\end{array}','Part (a) analyzes a loop structure. The loop iterates from x=2 to 6. For x=2, 3, and 4, the condition x > 4 is false, so printf executes. When x=5, the condition x > 4 is true, and the break statement terminates the loop immediately. Thus, only 2, 3, and 4 are printed. Part (b) analyzes the post-increment operator (num++). The expression a = num++ assigns the current value of num (10) to \'a\' before incrementing num to 11. Therefore, after the operation, num is 11 and a is 10.','a) \\text{Iteration 1: } x=2, x \\le 6, x>4 \\text{ is false, print 2.} \\\\ \\text{Iteration 2: } x=3, x \\le 6, x>4 \\text{ is false, print 3.} \\\\ \\text{Iteration 3: } x=4, x \\le 6, x>4 \\text{ is false, print 4.} \\\\ \\text{Iteration 4: } x=5, x \\le 6, x>4 \\text{ is true, execute break.} \\\\ \\text{Result: } 234. \\\\ \\text{b) Let } num=10. \\text{ The post-increment operator } num++ \\text{ assigns the original value of } num \\text{ to } a \\text{ then increments } num. \\\\ a = 10, num = 11. \\\\ \\text{Output: num is 11, a is 10.}','a) 234; b) num is 11, a is 10','["Loops", "Operators", "Output Tracing", "Programming Concepts"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('a500ee224a71af359963ed84ec19f17a2a232f08fba7a442c0b17489b51dfb7b','End Semester','Programming for Problem Solving','CS24101','2','2023','Q.2(b)','Explain the following with the help of an example: a) Implicit and explicit type conversion b) Comparison between while and do while loop.','\\text{Explain the following with the help of an example: a) Implicit and explicit type conversion b) Comparison between while and do while loop.}','a) Type conversion refers to changing an expression from one data type to another. 1. Implicit Conversion: Automatically performed by the compiler when compatible types are mixed. Example: int x = 10; float y = x; (x becomes 10.0 automatically). 2. Explicit Conversion (Type Casting): Manually performed by the programmer using a cast operator. Example: float f = 10.5; int i = (int)f; (f is truncated to 10). b) Comparison between while and do-while loops: 1. Entry Condition: While is an entry-controlled loop (condition checked before execution); do-while is an exit-controlled loop (condition checked after execution). 2. Execution Guarantee: While may execute zero times; do-while executes at least once. 3. Syntax: While(condition) { body }; Do { body } while(condition);','\\text{a) Type Conversion: } \\\\ 1. \\text{ Implicit: Automatic promotion. Ex: } \\text{int } a = 5; \\text{ float } b = a; \\implies b=5.0. \\\\ 2. \\text{ Explicit: Manual casting. Ex: } \\text{double } d = 9.7; \\text{ int } i = (int)d; \\implies i=9. \\\\ \\text{b) Loop Comparison: } \\\\ \\begin{array}{|l|l|l|} \\hline \\text{Feature} & \\text{while} & \\text{do-while} \\\\ \\hline \\text{Check} & \\text{Before execution} & \\text{After execution} \\\\ \\hline \\text{Min Execution} & 0 & 1 \\\\ \\hline \\text{Syntax} & \\text{while(cond)\\{...\\}} & \\text{do\\{...\\}while(cond);} \\\\ \\hline \\end{array}','Implicit: automatic promotion; Explicit: manual casting via (type). while: entry-controlled (0+ iterations); do-while: exit-controlled (1+ iterations).','["Loops", "Type Conversion"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('e2799a5d6916453824ace17caeb63dc1011010acc29a850430e13becc0b1d5e5','End Semester','Programming for Problem Solving','CS24101','3','2023','Q.3(a)','Explain the following with the help of an example: 1) Array (Single and Multiple Dimension) 2) strings related built-in functions (any two).','\\text{Explain the following with the help of an example: 1) Array (Single and Multiple Dimension) 2) strings related built-in functions (any two).}','1. Arrays are collections of elements of the same data type stored in contiguous memory. A single-dimensional array acts as a list, while a multi-dimensional array acts as a table or higher-dimensional grid. Example: int arr[5] = {1, 2, 3, 4, 5} (1D) and int matrix[2][2] = {{1, 2}, {3, 4}} (2D). 2. Built-in string functions: (a) strlen(): calculates the length of a string (e.g., strlen(\'Hello\') returns 5). (b) strcpy(): copies one string to another (e.g., strcpy(dest, src) copies src into dest).','1) \\textbf{Array}: An array is a collection of uniform data elements. \\\\ Single-dimensional: A list structure. Example: \\text{int a[3] = {10, 20, 30};} \\\\ Multi-dimensional: An array of arrays (e.g., a matrix). Example: \\text{int m[2][2] = {{1, 2}, {3, 4}};} \\\\ 2) \\textbf{Built-in String Functions}: \\\\ a) \\text{strlen(s)}: Returns the number of characters in string s. Example: \\text{strlen("ABC")} \\rightarrow 3. \\\\ b) \\text{strcpy(dest, src)}: Copies string src to dest. Example: \\text{strcpy(s1, "Hello");}','Array (1D/2D) allows contiguous storage; strlen() returns length, strcpy() copies content.','["Arrays", "Programming Concepts", "Strings"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('e63c4ec6738cb25bbcef2e418d78fb29e6d185d2cdb9fe77bfb027d294cf380a','End Semester','Programming for Problem Solving','CS24101','3','2023','Q.3(b)','Store and display the following numbers in a matrix of order 3 X 4 using a 2D array: 10 30 20 40 15 25 35 45 15 5 25 35 Find the row sum and column sum of the matrix.','\\text{Store and display the following numbers in a matrix of order } 3 \\times 4 \\text{ using a 2D array:} \\\\ \\begin{matrix} 10 & 30 & 20 & 40 \\\\ 15 & 25 & 35 & 45 \\\\ 15 & 5 & 25 & 35 \\end{matrix} \\\\ \\text{Find the row sum and column sum of the matrix.}','1. Define a 3x4 2D array and populate it with the given values. 2. To calculate row sums, iterate through each row (i=0 to 2) and compute the sum of all elements in that row. 3. To calculate column sums, iterate through each column (j=0 to 3) and compute the sum of all elements in that column. 4. Row sums are as follows: Row 0 = 10+30+20+40 = 100, Row 1 = 15+25+35+45 = 120, Row 2 = 15+5+25+35 = 80. 5. Column sums are as follows: Col 0 = 10+15+15 = 40, Col 1 = 30+25+5 = 60, Col 2 = 20+35+25 = 80, Col 3 = 40+45+35 = 120.','\\text{Given matrix } A = \\begin{pmatrix} 10 & 30 & 20 & 40 \\\\ 15 & 25 & 35 & 45 \\\\ 15 & 5 & 25 & 35 \\end{pmatrix} \\\\ \\text{Row Sums:} \\\\ R_0 = 10+30+20+40 = 100 \\\\ R_1 = 15+25+35+45 = 120 \\\\ R_2 = 15+5+25+35 = 80 \\\\ \\text{Column Sums:} \\\\ C_0 = 10+15+15 = 40 \\\\ C_1 = 30+25+5 = 60 \\\\ C_2 = 20+35+25 = 80 \\\\ C_3 = 40+45+35 = 120','Row sums: {100, 120, 80}; Column sums: {40, 60, 80, 120}','["2D Arrays", "Matrix", "Programming Concepts"]','programming','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('fd33d974b42b36b4c3e198b87104f43a140ba48fae8bef2590a26a077f91fcb9','End Semester','Programming for Problem Solving','CS24101','3','2023','Q.4(a)','Explain briefly about the bubble sort algorithm or program. Sort the following numbers using the bubble sort algorithm: 15, 10, 5, 3, 20, 16, 12, 9.','\\text{Explain briefly about the bubble sort algorithm or program. Sort the following numbers using the bubble sort algorithm: } 15, 10, 5, 3, 20, 16, 12, 9.','Bubble Sort is a simple comparison-based sorting algorithm that repeatedly steps through the list, compares adjacent elements, and swaps them if they are in the wrong order. This process repeats until the list is sorted. The pass through the list is repeated until no swaps are needed. For the input [15, 10, 5, 3, 20, 16, 12, 9]: Pass 1: [10, 5, 3, 15, 16, 12, 9, 20]. Pass 2: [5, 3, 10, 15, 12, 9, 16, 20]. Pass 3: [3, 5, 10, 12, 9, 15, 16, 20]. Pass 4: [3, 5, 10, 9, 12, 15, 16, 20]. Pass 5: [3, 5, 9, 10, 12, 15, 16, 20]. Since no further swaps are required, the list is sorted.','\\text{Bubble sort operates by comparing adjacent elements } (a_i, a_{i+1}) \\text{ and swapping if } a_i > a_{i+1}. \\text{ Given: } [15, 10, 5, 3, 20, 16, 12, 9] \\\\ \\text{Pass 1: } [10, 5, 3, 15, 16, 12, 9, 20] \\\\ \\text{Pass 2: } [5, 3, 10, 15, 12, 9, 16, 20] \\\\ \\text{Pass 3: } [3, 5, 10, 12, 9, 15, 16, 20] \\\\ \\text{Pass 4: } [3, 5, 10, 9, 12, 15, 16, 20] \\\\ \\text{Pass 5: } [3, 5, 9, 10, 12, 15, 16, 20] \\\\ \\text{Result: The array is sorted as } [3, 5, 9, 10, 12, 15, 16, 20].','3, 5, 9, 10, 12, 15, 16, 20','["Algorithms", "Bubble Sort", "Sorting Algorithms"]','analytical','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('961fe016b122727e34a0d8f06644fb5ac4ba440061c4adfda627c37ef611697e','End Semester','Programming for Problem Solving','CS24101','4','2023','Q.4(b)','Write a program in C language to solve the factorial of a number using recursive and non-recursive functions.','\\text{Write a program in C language to solve the factorial of a number using recursive and non-recursive functions.}','1. To calculate the factorial of a non-negative integer n (denoted as n!), we define the product: n! = n * (n-1) * ... * 1, with 0! = 1. 2. For the non-recursive approach, we use an iterative loop (e.g., a for-loop) that starts from 1 and multiplies a result variable by every integer up to n. 3. For the recursive approach, we use the property that n! = n * (n-1)! for n > 0 and 0! = 1. The function calls itself until it reaches the base case. 4. In C, we implement both methods using long long int to handle large factorial values.','\\text{The factorial } n! \\text{ is defined as: } n! = \\prod_{i=1}^{n} i = n \\times (n-1) \\times \\dots \\times 1 \\text{ for } n > 0, \\text{ and } 0! = 1. \\\\ \\text{Iterative Logic: } \\text{result} = 1; \\text{for } i=1 \\text{ to } n: \\text{result} = \\text{result} \\times i. \\\\ \\text{Recursive Logic: } f(n) = \\begin{cases} 1 & \\text{if } n=0 \\\\ n \\times f(n-1) & \\text{if } n>0 \\end{cases}','Implemented via iterative loop (result *= i) and recursive function (n * factorial(n-1)).','["Functions", "Programming Concepts", "Recursion"]','programming','1.0',0,1,'gemini-3.1-flash-lite','5','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('93355470cf0e4f4fcd07c226fff9ff591684f859e4900261f24975687da5decc','Lab Assignment','Programming for Problem Solving','CS24101','2','2026','Q.1','Write a program to print HELLO WORLD on screen.','\\text{Write a program to print HELLO WORLD on screen.}','Step 1: Include the standard input-output library (stdio.h) to use the printf function. Step 2: Define the main function, which serves as the entry point of the program. Step 3: Inside the main function, use the printf statement followed by the string "HELLO WORLD" enclosed in double quotes. Step 4: Include a newline character if necessary for formatting, and terminate the statement with a semicolon. Step 5: Return 0 to indicate successful execution.','\\text{Step 1: } \\#include <stdio.h> \\newline \\text{Step 2: int main() \\{ } \\newline \\text{Step 3: printf("HELLO WORLD"); } \\newline \\text{Step 4: return 0; } \\newline \\text{Step 5: \\}}','#include <stdio.h>\nint main() {\n    printf("HELLO WORLD");\n    return 0;\n}','["Basic I/O", "Programs"]','programming','1.0',0,1,'gemini-3.1-flash-lite','1','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('6147e5d145b62a7cfaa8c76b9a12f207a5b4d7e9782deb33a9b905a4f26692f2','Lab Assignment','Programming for Problem Solving','CS24101','2','2026','Q.3','Write a program which accept two numbers and print their sum.','\\text{Write a program which accept two numbers and print their sum.}','Step 1: Declare two variables (e.g., num1 and num2) to store the input numbers. Step 2: Accept the values for these variables from the user using an input function. Step 3: Calculate the sum by adding the two variables together (sum = num1 + num2). Step 4: Output the result using a print function.','\\text{Step 1: Declare two variables } a, b \\in \\mathbb{R}. \\\\ \\text{Step 2: Read input } a \\text{ and } b. \\\\ \\text{Step 3: Calculate } S = a + b. \\\\ \\text{Step 4: Print } S.','S = a + b','["Arithmetic Operators", "Basic I/O"]','programming','1.0',0,1,'gemini-3.1-flash-lite','1','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('22c115d5c31684216b97e6df35f73e2fe701a866cff45ec2d04c81cd2ac54fc3','Lab Assignment','Programming for Problem Solving','CS24101','2','2026','Q.4','Write a program which accept temperature in Farenheit and print it in centigrade.','\\text{Write a program which accept temperature in Farenheit and print it in centigrade.}','To convert temperature from Fahrenheit (F) to Centigrade or Celsius (C), use the formula C = (F - 32) * 5/9. 1. Accept the Fahrenheit value from the user as input. 2. Subtract 32 from the input value. 3. Multiply the result by 5. 4. Divide the result by 9. 5. Output the calculated Centigrade value.','The conversion formula from Fahrenheit (F) to Celsius (C) is defined as: C = \\frac{5}{9} \\times (F - 32). The algorithm is as follows: 1. \\text{Input } F. 2. \\text{Calculate } T_{diff} = F - 32. 3. \\text{Calculate } C = T_{diff} \\times \\frac{5}{9}. 4. \\text{Output } C.','C = \\frac{5}{9}(F - 32)','["Arithmetic Programs", "Expressions"]','programming','1.0',0,1,'gemini-3.1-flash-lite','1','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('5f8f16d7ca1721cda1b684333510dd56845b47497b9178dcbd7b8a9182d74546','Lab Assignment','Programming for Problem Solving','CS24101','2','2026','Q.5','Write a program which accept principle, rate and time from user and print the simple interest.','\\text{Write a program which accept principle, rate and time from user and print the simple interest.}','Step 1: Accept the input values for principal (P), rate of interest (R), and time (T) from the user. Step 2: Calculate the simple interest using the formula: SI = (P * R * T) / 100. Step 3: Display the calculated simple interest value to the user.','\\text{Step 1: Let } P, R, \\text{ and } T \\text{ be the principal, rate, and time.} \\\\ \\text{Step 2: The formula for Simple Interest is } SI = \\frac{P \\times R \\times T}{100}. \\\\ \\text{Step 3: Output the resulting value of } SI.','SI = (P * R * T) / 100','["Arithmetic Programs", "Expressions"]','programming','1.0',0,1,'gemini-3.1-flash-lite','1','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('3863e5185fd4e1295893303f1022e0256810085591d1f86dc6ed38f593877a60','Lab Assignment','Programming for Problem Solving','CS24101','2','2026','Q.6','Write a program which accepts a character and display its ASCII value.','\\text{Write a program which accepts a character and display its ASCII value.}','Step 1: Declare a variable of type char to store the user input. Step 2: Use an input function (like scanf or cin) to accept a character from the user. Step 3: To find the ASCII value, cast the character variable to an integer type. In C/C++, when a char is assigned to or printed as an integer, the system automatically treats it as its ASCII numerical value. Step 4: Display the result using an output function (like printf or cout) by formatting it as an integer.','\\text{Step 1: Declare } \\text{char } c; \\text{ Step 2: Accept input into } c. \\text{ Step 3: Cast } c \\text{ to integer type } (int)c. \\text{ Step 4: The ASCII value is given by the implicit mapping of character literals to their corresponding decimal integer values in the ASCII table, typically ranging from 0 to 127.}','printf("ASCII value is %d", (int)c);','["Basic I/O", "Data Types"]','programming','1.0',0,1,'gemini-3.1-flash-lite','1','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('948073618d47471e3a6d776e46b9383654ec84b8bf586a9573b99d479ecc0277','Lab Assignment','Programming for Problem Solving','CS24101','2','2026','Q.7','Write a program to swap the values of two variables.','\\text{Write a program to swap the values of two variables.}','To swap two variables \'a\' and \'b\', we use a third temporary variable \'temp\'. Step 1: Assign the value of \'a\' to \'temp\'. Step 2: Assign the value of \'b\' to \'a\'. Step 3: Assign the value of \'temp\' to \'b\'. This process ensures the values are exchanged without data loss.','\\text{Let } a, b \\in \\mathbb{R} \\text{ be two variables.} \\\\ \\text{Step 1: } temp \\leftarrow a \\\\ \\text{Step 2: } a \\leftarrow b \\\\ \\text{Step 3: } b \\leftarrow temp \\\\ \\therefore \\text{After execution, the values are swapped.}','temp = a; a = b; b = temp;','["Basic Logic", "Variables"]','programming','1.0',0,1,'gemini-3.1-flash-lite','1','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('cdf14c76e2360fa80dbe679d1ec33b62d59a53c82425f7edd013a711ec845aeb','Lab Assignment','Programming for Problem Solving','CS24101','2','2026','Q.8','Write a program to calculate area of circle.','\\text{Write a program to calculate area of circle.}','1. Identify the formula for the area of a circle: Area = π * r^2, where r is the radius.\n2. Define the input: Prompt the user to enter the radius of the circle.\n3. Implement the calculation: Use the constant π (approximately 3.14159) and multiply it by the square of the radius.\n4. Output the result: Display the calculated area to the user.\n5. Example C code: Include <stdio.h>, define main, declare float r and area, use scanf for input, calculate area = 3.14159 * r * r, and print the result using printf.','\\text{Step 1: Formula for Area of a Circle: } A = \\pi r^2 \\\\ \\text{Step 2: Input radius } r \\in \\mathbb{R}^+ \\\\ \\text{Step 3: Compute } A = 3.14159 \\times r \\times r \\\\ \\text{Step 4: Output result } A \\\\ \\text{Code snippet: } \\texttt{area = 3.14159 * r * r;}','Area = \\pi r^2','["Arithmetic Programs", "Expressions"]','programming','1.0',0,1,'gemini-3.1-flash-lite','1','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('5388989431c250186b1556b1c39a013a373b0d2ff676d52b5da200a46e7e2bf4','Lab Assignment','Programming for Problem Solving','CS24101','2','2026','Q.9','Write a program to check whether the given number is positive or negative (using ? : ternary operator ).','\\text{Write a program to check whether the given number is positive or negative (using ? : ternary operator ).}','1. Initialize a variable to store the input number. 2. Use the ternary operator (? :) to evaluate the condition: if the number is greater than or equal to 0, it is positive; otherwise, it is negative. 3. Print the result based on the boolean evaluation. For example, in C, the expression (num >= 0 ? "Positive" : "Negative") directly evaluates the sign.','\\text{Step 1: Declare an integer variable } n. \\\\ \\text{Step 2: Read the input value for } n. \\\\ \\text{Step 3: Apply the ternary operator: } (n \\ge 0) ? \\text{printf("Positive")} : \\text{printf("Negative")}. \\\\ \\text{Step 4: Terminate the program.}','(n >= 0 ? "Positive" : "Negative")','["Conditional Branching", "Operators"]','programming','1.0',0,1,'gemini-3.1-flash-lite','1','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('83c42c8404ce64565cab28b444ab4a8ceeaef6ad7a4c05fb39a089c7817b1b16','Lab Assignment','Programming for Problem Solving','CS24101','2','2026','Q.10','Write a program to check whether the given number is even or odd (using ? : ternary operator ).','\\text{Write a program to check whether the given number is even or odd (using ? : ternary operator ).}','Step 1: Accept an integer input from the user. Step 2: Use the ternary operator (condition ? expression_if_true : expression_if_false) to check if the remainder of the number divided by 2 is 0. If the condition (num % 2 == 0) is true, the number is even; otherwise, it is odd. Step 3: Print the result.','\\text{Step 1: Input integer } n. \\\\ \\text{Step 2: Apply the ternary operator expression: } (n \\% 2 == 0) ? \\text{ "Even"} : \\text{ "Odd"}. \\\\ \\text{Step 3: Output the resulting string.}','(n % 2 == 0) ? "Even" : "Odd"','["Conditional Branching", "Operators"]','programming','1.0',0,1,'gemini-3.1-flash-lite','1','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('60b90518597119485bf61cad487c53100461076ede0c027648ed4ff12c40bcdc','Lab Assignment','Programming for Problem Solving','CS24101','2','2026','Q.11','Write a program to swap value of two variables without using third variable.','\\text{Write a program to swap value of two variables without using third variable.}','To swap two variables \'a\' and \'b\' without a third variable, we use arithmetic operations. 1. Add both values and store the result in \'a\' (a = a + b). 2. Subtract the new \'a\' from \'b\' and store the result in \'b\' (b = a - b), which effectively sets \'b\' to the original \'a\'. 3. Subtract the new \'b\' from \'a\' and store the result in \'a\' (a = a - b), which effectively sets \'a\' to the original \'b\'.','Let the initial values be a = x and b = y. \\\\ 1. a = a + b \\Rightarrow a = x + y \\\\ 2. b = a - b \\Rightarrow b = (x + y) - y = x \\\\ 3. a = a - b \\Rightarrow a = (x + y) - x = y \\\\ Result: a = y, b = x.','a = a + b; b = a - b; a = a - b;','["Arithmetic Operators", "Variables"]','programming','1.0',0,1,'gemini-3.1-flash-lite','1','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('3e1e215a05fdf5c59777b4504b47529cc3b63208d0eddc7ce25c15543606cb4c','Lab Assignment','Programming for Problem Solving','CS24101','2','2026','Q.12','Write a program which input three numbers and display the largest number using ternary operator.','\\text{Write a program which input three numbers and display the largest number using ternary operator.}','1. Initialize three variables (a, b, and c) to store the user input. 2. Use the ternary operator (? :) to compare the variables. 3. First, compare \'a\' with \'b\' and \'c\' to determine the largest. Specifically, evaluate whether a > b and a > c; if true, a is the largest. 4. If false, evaluate whether b > c. If true, b is the largest. 5. Otherwise, c is the largest. 6. Display the result using the expression: (a > b && a > c) ? a : (b > c ? b : c).','\\text{Let } a, b, \\text{ and } c \\text{ be the three input numbers.} \\\\ \\text{The logic using nested ternary operators is defined as: } \\\\ \\text{max} = (a > b \\land a > c) ? a : (b > c ? b : c) \\\\ \\text{This expression evaluates the condition: if } a \\text{ is greater than both } b \\text{ and } c, \\text{ return } a. \\\\ \\text{Otherwise, evaluate if } b > c; \\text{ if true, return } b, \\text{ else return } c.','max = (a > b && a > c) ? a : (b > c ? b : c);','["Conditional Branching", "Operators"]','programming','1.0',0,1,'gemini-3.1-flash-lite','1','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('d32222001f4d13f1de7ecffe054440df5dab2a607bf1527eabd2e620924bf17d','Lab Assignment','Programming for Problem Solving','CS24101','2','2026','Q.13','Write a program which accepts amount as integer and display total number of Notes of Rs. 500, 100, 50, 20, 10, 5 and 1.','\\text{Write a program which accepts amount as integer and display total number of Notes of Rs. 500, 100, 50, 20, 10, 5 and 1.}','To solve this problem, we calculate the number of notes for each denomination by greedily taking the largest possible denomination first. 1. Accept the total amount as an integer. 2. Divide the amount by 500 to find the count of 500-rupee notes; update the amount to the remainder using the modulo operator. 3. Repeat this process sequentially for 100, 50, 20, 10, 5, and 1. 4. Display the count for each note denomination.','Let A be the input amount. The number of notes N_i for a denomination D_i is given by N_i = \\lfloor A / D_i \\rfloor, and the remaining amount is A \\leftarrow A \\pmod{D_i}. The sequence of denominations is D = \\{500, 100, 50, 20, 10, 5, 1\\}. For each D_i \\in D: N_{500} = \\lfloor A/500 \\rfloor, A = A \\pmod{500}; N_{100} = \\lfloor A/100 \\rfloor, A = A \\pmod{100}; N_{50} = \\lfloor A/50 \\rfloor, A = A \\pmod{50}; N_{20} = \\lfloor A/20 \\rfloor, A = A \\pmod{20}; N_{10} = \\lfloor A/10 \\rfloor, A = A \\pmod{10}; N_{5} = \\lfloor A/5 \\rfloor, A = A \\pmod{5}; N_{1} = A.','N_i = \\lfloor A/D_i \\rfloor','["Arithmetic Programs", "Basic Logic"]','programming','1.0',0,1,'gemini-3.1-flash-lite','1','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('125a340f461df83260bf8df53bf7aff2b983cafed3cfb2703a6188e86303d705','Lab Assignment','Programming for Problem Solving','CS24101','2','2026','Q.14','Write a program which accepts a character and display its next character.','\\text{Write a program which accepts a character and display its next character.}','1. Initialize a variable to hold the input character. 2. Accept the character from the user using an input function. 3. Since characters are stored as ASCII values in memory, increment the character\'s value by 1. 4. Display the resulting character. Example: If input is \'A\' (ASCII 65), the program performs 65 + 1 = 66, which corresponds to \'B\'.','1. \\text{Let } c \\in \\mathbb{Z} \\text{ be the ASCII representation of the input character.} \\\\ 2. \\text{The next character is obtained by the operation } c\' = c + 1. \\\\ 3. \\text{The result is the character associated with the integer } c\'.','next_char = char + 1','["Arithmetic Operators", "Data Types"]','programming','1.0',0,1,'gemini-3.1-flash-lite','1','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('a8f374c4d80e0d2daf2473c069b434844bc219a56cb2d4873b911520b72ee8c3','Lab Assignment','Programming for Problem Solving','CS24101','2','2026','Q.15','Write a program which accepts days as integer and display total number of years, months and days in it. for example : If user input as 856 days the output should be 2 years 4 months 6 days.','\\text{Write a program which accepts days as integer and display total number of years, months and days in it. for example : If user input as 856 days the output should be 2 years 4 months 6 days.}','1. Accept the total number of days as an integer input from the user. 2. Calculate the number of years by performing integer division of the total days by 365. 3. Calculate the remaining days after extracting full years by using the modulo operator (total_days % 365). 4. Calculate the number of months by performing integer division of the remaining days by 30. 5. Calculate the remaining days by performing a modulo operation of the remaining days from step 3 by 30. 6. Display the calculated years, months, and days.','\\text{Let } D \\text{ be the total days.} \\\\ \\text{1. } Y = \\lfloor D / 365 \\rfloor \\\\ \\text{2. } R = D \\pmod{365} \\\\ \\text{3. } M = \\lfloor R / 30 \\rfloor \\\\ \\text{4. } d = R \\pmod{30} \\\\ \\text{Result: } Y \\text{ years, } M \\text{ months, } d \\text{ days.} \\\\ \\text{Example for 856: } Y = \\lfloor 856 / 365 \\rfloor = 2, R = 126, M = \\lfloor 126 / 30 \\rfloor = 4, d = 6. \\text{ Output: 2 years 4 months 6 days.}','Y = D // 365, M = (D % 365) // 30, d = (D % 365) % 30','["Arithmetic Programs", "Basic Logic"]','programming','1.0',0,1,'gemini-3.1-flash-lite','1','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('4984dd583bcfa7dfc2d9b6b4faf68023a77ca058e6b2a287c5cce1ca11167028','Lab Assignment','Programming for Problem Solving','CS24101','4','2026','Q.80','Write a function in C which accepts a 2D array of integers and its size as arguments and displays the elements of middle row and the elements of middle column. [Assuming the 2D Array to be a square matrix with odd dimension i.e. 3x3, 5x5, 7x7 etc...]','\\text{Write a function in C which accepts a 2D array of integers and its size as arguments and displays the elements of middle row and the elements of middle column. [Assuming the 2D Array to be a square matrix with odd dimension i.e. 3x3, 5x5, 7x7 etc...]}','1. Identify the middle index: For a square matrix of size n x n where n is odd, the middle row and middle column index is calculated as mid = n / 2. 2. Iterate through the matrix: Use a loop to traverse the elements. Since we only need the middle row and column, we can iterate from i = 0 to n-1. 3. Access elements: The elements of the middle row are accessed by fixing the row index as \'mid\' and varying the column index (matrix[mid][i]). The elements of the middle column are accessed by fixing the column index as \'mid\' and varying the row index (matrix[i][mid]). 4. Print results: To avoid printing the central element (the intersection) twice, check if the current iteration index equals the middle index and skip printing for the second traversal or simply handle the intersection point logic.','Given a matrix A of size n \\times n, where n is odd. The middle index is m = \\lfloor n/2 \\rfloor. The middle row elements are given by A[m][j] for j \\in \\{0, 1, ..., n-1\\}. The middle column elements are given by A[i][m] for i \\in \\{0, 1, ..., n-1\\}. The C implementation is: void displayMiddle(int n, int mat[n][n]) { int m = n / 2; printf(\\"Middle Row: \\"); for(int i=0; i<n; i++) printf(\\"%d \\", mat[m][i]); printf(\\"\\\\nMiddle Column: \\"); for(int i=0; i<n; i++) printf(\\"%d \\", mat[i][m]); }','void displayMiddle(int n, int mat[n][n]) { int m = n/2; for(int i=0; i<n; i++) printf("%d ", mat[m][i]); for(int i=0; i<n; i++) printf("%d ", mat[i][m]); }','["2D Arrays", "Functions", "Programming Concepts"]','programming','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('cd58dbc6ebee96a7a9a97ed37846f9b0d11f0a41db0b91b1d530e451d6f663c1','Lab Assignment','Programming for Problem Solving','CS24101','3','2026','Q.81','Write a program to add two array A and B of size m x n.','\\text{Write a program to add two array A and B of size m x n.}','1. Initialize two 2D arrays A and B of size m x n and a resultant array C of the same size. 2. Use nested loops to iterate through each row index i (from 0 to m-1) and column index j (from 0 to n-1). 3. For every position (i, j), calculate the sum of corresponding elements from A and B: C[i][j] = A[i][j] + B[i][j]. 4. Store the result in array C. 5. Print the matrix C.','\\text{Given two matrices } A_{m \\times n} \\text{ and } B_{m \\times n}. \\text{ The sum matrix } C_{m \\times n} \\text{ is defined as: } C_{i,j} = A_{i,j} + B_{i,j} \\text{ for all } 0 \\le i < m \\text{ and } 0 \\le j < n. \\text{ In C programming: } \\text{for } (i=0; i < m; i++) \\{ \\text{for } (j=0; j < n; j++) \\{ C[i][j] = A[i][j] + B[i][j]; \\} \\}','C[i][j] = A[i][j] + B[i][j]','["2D Arrays", "Matrix Operations", "Programming Concepts"]','programming','1.0',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('23e3ee534d0d31d76eb0de83e5107fd7ebb17494a6378686f63abd24a856e417','Lab Assignment','Programming for Problem Solving','CS24101','3','2026','Q.82','Write a program to multiply array A and B of order NxL and LxM.','\\text{Write a program to multiply array A and B of order NxL and LxM.}','1. Initialize three matrices: A of size NxL, B of size LxM, and Result (C) of size NxM. 2. Use three nested loops: the outermost loop iterates through rows of A (i from 0 to N-1), the middle loop through columns of B (j from 0 to M-1), and the innermost loop through the common dimension (k from 0 to L-1). 3. In the innermost loop, perform the operation: C[i][j] += A[i][k] * B[k][j]. 4. Initialize C[i][j] to zero before starting the inner loop. 5. Output the resulting matrix C.','Given matrix A of dimension N \\times L and matrix B of dimension L \\times M, the product matrix C = A \\times B will have dimensions N \\times M. Each element c_{ij} is calculated as the dot product of the i-th row of A and the j-th column of B: c_{ij} = \\sum_{k=0}^{L-1} a_{ik} \\cdot b_{kj}. The algorithm complexity is O(N \\cdot L \\cdot M). Steps: 1. Initialize C_{N \\times M} with zeros. 2. For i = 0 to N-1: 3. For j = 0 to M-1: 4. For k = 0 to L-1: 5. C_{ij} = C_{ij} + A_{ik} \\times B_{kj}.','C_{ij} = \\sum_{k=0}^{L-1} A_{ik} B_{kj}','["2D Arrays", "Matrix Operations", "Programming Concepts"]','programming','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('c411ad6e29dd0c6a4b03595e19b98422f2ebf65ebfcfadb37fe2c09acd704cb8','Lab Assignment','Programming for Problem Solving','CS24101','5','2026','Q.83','Declare a structure to represent a complex number (a number having a real part and imaginary part). Write functions to add, subtract, multiply and divide two complex numbers.','\\text{Declare a structure to represent a complex number (a number having a real part and imaginary part). Write functions to add, subtract, multiply and divide two complex numbers.}','Step 1: Define a structure \'Complex\' containing two floating-point members: \'real\' and \'imag\'. Step 2: Implement addition by summing real and imaginary parts separately. Step 3: Implement subtraction by finding the difference of corresponding parts. Step 4: Implement multiplication using the FOIL method (a+bi)(c+di) = (ac-bd) + (ad+bc)i. Step 5: Implement division by multiplying the numerator and denominator by the conjugate of the denominator, resulting in ((ac+bd)/(c^2+d^2)) + ((bc-ad)/(c^2+d^2))i.','struct Complex { float real; float imag; }; \\\\ Complex add(Complex a, Complex b) { return {a.real + b.real, a.imag + b.imag}; } \\\\ Complex subtract(Complex a, Complex b) { return {a.real - b.real, a.imag - b.imag}; } \\\\ Complex multiply(Complex a, Complex b) { return {a.real*b.real - a.imag*b.imag, a.real*b.imag + a.imag*b.real}; } \\\\ Complex divide(Complex a, Complex b) { float den = b.real*b.real + b.imag*b.imag; return {(a.real*b.real + a.imag*b.imag)/den, (a.imag*b.real - a.real*b.imag)/den}; }','struct Complex { float real; float imag; }; Operations defined via real/imag component arithmetic.','["Functions", "Programming Concepts", "Structures"]','programming','1.0',0,1,'gemini-3.1-flash-lite','4','hard') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('0d870fc7f60c49f8bb2aeab258f52243ab755855fe5a83a585723aa19a49a551','Lab Assignment','Programming for Problem Solving','CS24101','5','2026','Q.84','An array stores details of 25 students (rollno, name, marks in three subject). Write a program to create such an array and print out a list of students who have failed in more than one subject.','\\text{An array stores details of 25 students (rollno, name, marks in three subject). Write a program to create such an array and print out a list of students who have failed in more than one subject.}','1. Define a structure named \'Student\' to hold rollno (integer), name (character array), and an array of marks for three subjects. 2. Declare an array of 25 such structures. 3. Initialize the array by taking user input for each student\'s roll number, name, and marks. 4. Iterate through the array using a loop. 5. For each student, check how many subjects have marks below the passing threshold (assume 40). 6. Maintain a counter for failed subjects for each student. 7. If the counter exceeds 1, print the student\'s name and roll number. 8. End the program.','\\text{1. Define a structure } Student \\{ int \\ rollno; \\ char \\ name[50]; \\ float \\ marks[3]; \\ \\}; \\\\ \\text{2. Declare } Student \\ s[25]; \\\\ \\text{3. Loop through } i=0 \\text{ to } 24: \\\\ \\quad \\text{a. Input } s[i].rollno, \\ s[i].name, \\ s[i].marks[0..2]. \\\\ \\quad \\text{b. Set } failCount = 0. \\\\ \\quad \\text{c. For } j=0 \\text{ to } 2: \\text{ if } s[i].marks[j] < 40, \\ failCount++. \\\\ \\quad \\text{d. If } failCount > 1, \\text{ print } s[i].name, \\ s[i].rollno.','A C/C++ program using a struct array and a nested loop counter to identify students with marks < 40 in more than one subject.','["Arrays of Structures", "Programming Concepts", "Structures"]','programming','1.0',0,1,'gemini-3.1-flash-lite','3','medium') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('cbfd4218f520c12dc8c462a253828d143673b8f46ad35f9eaf666d7446b922bf','Objective Question Bank','Programming for Problem Solving','CS24101','3','2026','Q.1','Which of the following correctly declares an array? A. int an array[10]; B. int an array; C. an array(10); D. array an array[10];','\\text{Which of the following correctly declares an array?} \\\\ \\text{A. int an array[10];} \\\\ \\text{B. int an array;} \\\\ \\text{C. an array\\{10\\};} \\\\ \\text{D. array an array[10];}','1. In C programming, an array declaration requires a data type, an identifier (name), and the array size enclosed in square brackets. 2. Option A (int an array[10];) is syntactically invalid because variable names cannot contain spaces. If the name were \'an_array\', it would be correct. However, evaluating the choices as written: 3. Option B is a simple integer declaration, not an array. 4. Option C uses parentheses which are for function calls or type casting. 5. Option D uses \'array\' as a data type, which is not a primitive type in C. Assuming the space in the identifier is a typographical error for a valid identifier, A is the intended structure for declaring an integer array of size 10.','\\text{1. To declare an array in C, the syntax is: } \\langle \\text{type} \\rangle \\; \\langle \\text{identifier} \\rangle [\\langle \\text{size} \\rangle]; \\\\ \\text{2. Analyzing the options:} \\\\ \\text{A. int an array[10]; (Invalid due to space in identifier, but matches structure)} \\\\ \\text{B. int an array; (Missing array brackets)} \\\\ \\text{C. an array(10); (Parentheses are for functions)} \\\\ \\text{D. array an array[10]; (Invalid data type)} \\\\ \\text{3. Assuming standard identifier naming rules where the space is a typo for an underscore, A follows the correct syntax.}','A','["Arrays", "Programming Concepts", "Syntax"]','conceptual','0.95',0,1,'gemini-3.1-flash-lite','1','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('d87ab561484076b79b88b1ae65e5692674fcf746f371f6dd18f9f98b15e17dcf','Objective Question Bank','Programming for Problem Solving','CS24101','3','2026','Q.2','What is the index number of the last element of an array with 29 elements? A. 29 B. 28 C. 0 D. Programmer-defined','\\text{What is the index number of the last element of an array with 29 elements?} \\\\ \\text{A. 29} \\\\ \\text{B. 28} \\\\ \\text{C. 0} \\\\ \\text{D. Programmer-defined}','In most standard programming languages, arrays are zero-indexed, meaning the first element is located at index 0. For an array containing n elements, the index of the first element is 0 and the index of the last element is n - 1. Given that the array has 29 elements, the index of the last element is 29 - 1 = 28.','\\text{In zero-indexed programming languages, the index } i \\text{ of an array of size } n \\text{ ranges from } 0 \\text{ to } n-1. \\\\ \\text{Given } n = 29: \\\\ \\text{Last index} = n - 1 = 29 - 1 = 28.','B','["Arrays", "Indexing", "Programming Concepts"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','1','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('e0f2cc3080cf1f8e2951a0c07b580693f3a37934f1a403ff995cf3e6d3e4fb5c','Objective Question Bank','Programming for Problem Solving','CS24101','3','2026','Q.3','Which of the following is a two-dimensional array? A. array anarray[20][20]; B. int anarray[20][20]; C. int array[20, 20]; D. char array[20];','\\text{Which of the following is a two-dimensional array?} \\\\ \\text{A. array anarray[20][20];} \\\\ \\text{B. int anarray[20][20];} \\\\ \\text{C. int array[20, 20];} \\\\ \\text{D. char array[20];}','1. In C and C++ programming languages, a two-dimensional array is declared by specifying two sets of brackets, where each bracket contains the dimension size (e.g., type name[rows][columns]). 2. Option A is invalid because \'array\' is not a standard data type in C. 3. Option B, \'int anarray[20][20];\', correctly follows the syntax: [data_type] [identifier][rows][columns]. 4. Option C uses a comma-separated index inside a single set of brackets, which is syntactically incorrect for multi-dimensional arrays in C. 5. Option D describes a one-dimensional array of characters. Therefore, B is the correct declaration.','\\text{Step 1: Analyze syntax for 2D arrays in C/C++. The standard declaration is } \\langle \\text{type} \\rangle \\; \\langle \\text{identifier} \\rangle [\\text{rows}][\\text{cols}]; \\text{.} \\\\ \\text{Step 2: Evaluate options:} \\\\ \\text{A. \'array\' is not a valid C keyword.} \\\\ \\text{B. \'int anarray[20][20];\' correctly defines an integer 2D array.} \\\\ \\text{C. \'int array[20, 20];\' is invalid syntax in C.} \\\\ \\text{D. \'char array[20];\' is a 1D array.} \\\\ \\text{Conclusion: B is the only valid 2D array declaration.}','B','["2D Arrays", "Programming Concepts", "Syntax"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','1','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('e50b04ede5976de7119ee494d2a86b41f5bae4bd7b2476395663d15d794decdd','Objective Question Bank','Programming for Problem Solving','CS24101','5','2026','Q.4','What will be output if you will compile and execute the following c code? #include<stdio.h> int main()( int i=320; char *ptr=(char *) i; printf("%d",*ptr); return 0; )','\\begin{array}{l} \\text{What will be output if you will compile and execute the following c code?} \\\\ \\texttt{\\#include<stdio.h>} \\\\ \\texttt{int main()\\{} \\\\ \\texttt{\\ \\ int i=320;} \\\\ \\texttt{\\ \\ char *ptr=(char *)\\&i;} \\\\ \\texttt{\\ \\ printf("\\%d",*ptr);} \\\\ \\texttt{\\ \\ return 0;} \\\\ \\texttt{\\}} \\end{array}','1. Analysis: The integer 320 is represented in hexadecimal as 0x0140 (since 256 + 64 = 320). On a little-endian machine, which is standard for modern architectures, this is stored in memory as the byte sequence [0x40, 0x01].\n2. Execution: The variable \'ptr\' is a char pointer pointing to the address of \'i\'. Dereferencing a char pointer to an integer essentially reads the first byte of that integer.\n3. Result: The first byte in memory is 0x40. 0x40 in decimal is 64.\n4. Note: If the machine were big-endian, the value would be 0x01 (decimal 1), but standard systems are little-endian.','\\text{1. Representation of 320 in hex: } 320 = 256 + 64 = 0x0140. \\\\ \\text{2. Memory layout (little-endian): The integer 320 occupies 4 bytes (e.g., 0x40, 0x01, 0x00, 0x00). } \\\\ \\text{3. Pointer behavior: } char *ptr = (char *)&i; \\text{ accesses the first byte of } i. \\\\ \\text{4. Calculation: The value at the first memory location is 0x40.} \\\\ \\text{5. Conversion: } 0x40 = 64_{10}. \\\\ \\text{Output: } 64','64','["Output Tracing", "Pointers", "Programming Concepts", "Typecasting"]','analytical','0.95',0,1,'gemini-3.1-flash-lite','2','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('d9c79012f4d430b6e60637dce856fe5f0d699aaf248820b9da96832ecc91fa73','Objective Question Bank','Programming for Problem Solving','CS24101','2','2026','Q.219','How do printf()\'s format specifiers %e and %f differ in their treatment of floating-point numbers? A. %e displays an argument of type double with trailing zeros; %f never displays trailing zeros. B. %e displays a double in engineering notation if the number is very small or very large. Otherwise, it behaves like %f and displays the number in decimal notation. C. %e always displays an argument of type double in engineering notation; %f always displays an argument of type double in decimal notation. D. %e expects a corresponding argument of type double; %f expects a corresponding argument of type float. E. %e and %f both expect a corresponding argument of type double and format it identically.','\\text{How do printf()\'s format specifiers \\%e and \\%f differ in their treatment of floating-point numbers?} \\\\ \\text{A. \\%e displays an argument of type double with trailing zeros; \\%f never displays trailing zeros.} \\\\ \\text{B. \\%e displays a double in engineering notation if the number is very small or very large. Otherwise, it behaves like \\%f...}','1. In C, the printf() function uses format specifiers to determine how to represent numerical data. 2. The %e specifier represents a floating-point number in exponential notation, characterized by a mantissa and an exponent (e.g., 1.234567e+02). 3. The %f specifier represents a floating-point number in fixed-point decimal notation (e.g., 123.456700). 4. In C, due to default argument promotion, both %e and %f expect an argument of type double when passed to variadic functions like printf(). 5. Option C accurately describes the fundamental difference: %e forces scientific/engineering exponential notation, while %f forces decimal notation.','\\text{1. The format specifier } \\%e \\text{ converts the floating-point argument to scientific notation of the form } [-]d.dddde\\pm dd. \\\\ \\text{2. The format specifier } \\%f \\text{ converts the floating-point argument to decimal notation of the form } [-]dddd.dddd. \\\\ \\text{3. Both specifiers expect arguments of type double. Therefore, the primary difference is the output format: } \\%e \\text{ uses exponential notation, and } \\%f \\text{ uses decimal notation.} \\\\ \\text{4. Comparing this to the options, choice C is the correct statement.}','C','["Basic I/O", "Format Specifiers"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','1','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);
INSERT INTO questions (question_uid,exam,subject,subject_code,module,year,question_number,question_text,question_latex,solution_text,solution_latex,final_answer,tags,question_type,confidence_score,is_verified,latex_valid,generated_by,marks,difficulty) VALUES ('46f4b9862bd335fec50ffdd8e09c6c6ff5a9f32e5d831c7b5e6eefdfc7d89146','Objective Question Bank','Programming for Problem Solving','CS24101','2','2026','Q.220','c = getchar(); What is the proper declaration for the variable c in the code above? A. char *c; B. char c; C. int c; D. float c;','\\text{c = getchar(); What is the proper declaration for the variable c in the code above?} \\\\ \\text{A. char *c; B. char c; C. int c; D. float c;}','1. The getchar() function in C is defined in the <stdio.h> library. 2. Its function prototype is \'int getchar(void);\'. 3. The function returns the next character from the input stream as an unsigned char cast to an int, or EOF if the end of the file is reached or an error occurs. 4. While declaring \'char c\' is common practice for simple applications, the function returns an int to accommodate the EOF constant, which is typically -1 and cannot be represented by a standard char type. Therefore, \'int c\' is the technically correct declaration to handle all return values, including EOF.','\\text{1. The getchar() function is defined as: int getchar(void);.} \\\\ \\text{2. It returns the next character as an } \\textit{unsigned char} \\text{ promoted to an } \\textit{int}, \\text{ or the macro } \\text{EOF} \\text{ on failure or end-of-file.} \\\\ \\text{3. Since EOF is typically defined as -1, it requires an integer type to be stored without overflow or misinterpretation.} \\\\ \\text{4. Thus, the proper declaration for the variable storing the result of getchar() is int c;}','C. int c;','["Basic I/O", "Data Types"]','conceptual','1.0',0,1,'gemini-3.1-flash-lite','1','easy') ON DUPLICATE KEY UPDATE solution_text=VALUES(solution_text),solution_latex=VALUES(solution_latex),final_answer=VALUES(final_answer),confidence_score=VALUES(confidence_score),generated_by=VALUES(generated_by);